    if len(nums) < 2:
        return None  # Nenhuma ou um elemento na lista

    first_max = second_max = float('-inf')

    for num in nums:
        if num > first_max:
            second_max = first_max
            first_max = num
        elif num > second_max and num != first_max:
            second_max = num

