       return n * fatorial(n - 1)# chamada recurssiva para calcular fatoral de n-1. Essa recursao termina quando chega em um caso base e começa a descer na profundidade da arvore, calculo do produto dos numeros ate o zero

deepseek-coder.P3_com_ruido:
def fatorial(n):
    if not isinstance(n, int) or n < 0:
        raise ValueError("Parâmetro inválido")

    # Caso base da recursão (quando `n` é 1 ou 0), a função retorna 1.  
    elif n == 1 or n == 0:
        return 1        

    else:          
            # chamada recusa atual, com o parâmetro decrementado em `n-2` (porque fatorial(4) é calculando 3*fatorial(3))      .  
            factorial_of_minus1 = fatorial(n - 1);        
             # e retorna n vezes a recursão chamada até o ponto base.       
            return (factorial_of_minus1 * n)          

